INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Outline the structure of the Earth.', 'Inner core (solid Fe/Ni, ~5500°C), outer core (liquid Fe/Ni, generates magnetic field), mantle (semi-molten silicates, convection cells), crust: oceanic (5-10 km, dense basalt) and continental (30-70 km, less dense granite).', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Explain plate motion via mantle convection, ridge push and slab pull.', 'Heat from radioactive decay drives mantle cells. Hot rock rises at ridges, pushes plates apart (ridge push). Cold dense oceanic lithosphere subducts, dragging the rest of the plate (slab pull — dominant force).', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Sketch the three plate-boundary types and their landforms.', 'Constructive (mid-ocean ridge, rift valley), destructive (subduction trench, volcanic arc), conservative (transform fault). <svg viewBox="0 0 280 150" width="280" height="150" style="display:block;margin:6px auto"><g><rect x="10" y="40" width="40" height="40" fill="#A0A0A0"/><rect x="60" y="40" width="40" height="40" fill="#A0A0A0"/><polygon points="50,40 60,40 55,20" fill="#B00020"/><line x1="20" y1="60" x2="0" y2="60" stroke="#0B1E3F" marker-end="url(#b1)"/><line x1="90" y1="60" x2="110" y2="60" stroke="#0B1E3F" marker-end="url(#b1)"/><text x="55" y="100" font-size="8" fill="#0B1E3F" text-anchor="middle">Constructive</text></g><g><rect x="120" y="40" width="50" height="40" fill="#A0A0A0"/><polygon points="170,40 215,80 215,40" fill="#A0A0A0"/><polygon points="195,40 175,40 175,55" fill="#9CC3E5"/><polygon points="180,40 200,40 190,25" fill="#B00020"/><line x1="155" y1="60" x2="180" y2="60" stroke="#0B1E3F" marker-end="url(#b1)"/><line x1="200" y1="60" x2="180" y2="60" stroke="#0B1E3F" marker-end="url(#b1)"/><text x="170" y="100" font-size="8" fill="#0B1E3F" text-anchor="middle">Destructive</text></g><g><rect x="225" y="40" width="50" height="40" fill="#A0A0A0"/><line x1="250" y1="40" x2="250" y2="80" stroke="white" stroke-width="2"/><line x1="240" y1="50" x2="260" y2="50" stroke="#0B1E3F" stroke-dasharray="2 2"/><line x1="230" y1="35" x2="245" y2="35" stroke="#0B1E3F" marker-end="url(#b1)"/><line x1="270" y1="85" x2="255" y2="85" stroke="#0B1E3F" marker-end="url(#b1)"/><text x="250" y="100" font-size="8" fill="#0B1E3F" text-anchor="middle">Conservative</text></g><defs><marker id="b1" viewBox="0 0 6 6" refX="5" refY="3" markerWidth="6" markerHeight="6" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#0B1E3F"/></marker></defs></svg>', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Define a hot spot with an example.', 'Mantle plumes that pierce moving plates and form volcanic chains as the plate moves over them (e.g. Hawaiian-Emperor seamount chain, Yellowstone caldera). Independent of plate boundaries.', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'How are earthquakes measured?', 'Magnitude (energy) on Moment Magnitude Scale (Mw, replaced Richter above ~M5; logarithmic). Intensity (effects) on Modified Mercalli (I-XII). Depth: shallow (<70 km) most damaging. Recorded by seismograph network.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Describe seismic waves: P, S and surface.', 'P (primary) waves: longitudinal compression, fastest, travel through solids and liquids. S (secondary): transverse, slower, only solids. Surface (Rayleigh, Love): slowest, largest amplitude, cause most damage.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'List four secondary effects of earthquakes.', 'Tsunami (Tohoku 2011), liquefaction (saturated sandy soils losing strength), landslides, fires (gas mains), disease, building collapse aftershocks. Often cause more deaths than primary shaking.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Explain how a tsunami forms.', 'Sudden vertical displacement of seabed (megathrust earthquake at subduction zone) lifts the entire water column. Long-wavelength waves travel ~700 km/h in deep ocean, slow and steepen on the shelf, surge inland.', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Compare a shield with a composite (stratovolcano).', 'Shield: low-viscosity basaltic lava, gentle slopes, frequent effusive eruptions (Mauna Loa). Composite: high-viscosity andesitic lava, steep alternating ash/lava layers, infrequent explosive eruptions (Mt St Helens, Vesuvius).', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'List four primary volcanic hazards.', 'Lava flows, pyroclastic flows (~700°C ash + gas avalanches, lethal — Pompeii AD79), tephra/ashfall, volcanic gases (SO2, CO2, HCl). Can also produce lahars (mudflows), tsunamis.', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Define VEI and explain its scale.', 'Volcanic Explosivity Index — logarithmic 0-8 based on ejecta volume and column height. VEI 0-2: effusive, frequent. VEI 5+: highly explosive (Mt St Helens 1980 = 5; Pinatubo 1991 = 6; Tambora 1815 = 7).', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Define hazard, risk, vulnerability and resilience.', 'Hazard: potential damaging event. Risk: probability × consequence. Vulnerability: degree to which a community is susceptible. Resilience: ability to absorb, adapt and recover. R = (H × V) / Capacity.', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Outline the Pressure and Release (PAR) model.', 'Disasters arise from the intersection of natural hazard and social vulnerability. Root causes (poverty, governance) -> dynamic pressures (rapid urbanisation, deforestation) -> unsafe conditions (slums on hillsides). Releases pressure by addressing causes.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Compare HIC and LIC earthquake responses.', 'Tohoku, Japan 2011 (Mw9.1): ~20,000 deaths, $235bn damage, advanced warning, building codes, swift recovery. Haiti 2010 (Mw7.0): ~230,000 deaths, weak buildings, slow recovery, lasting cholera outbreak.', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Outline tropical storm formation conditions.', 'Forms over oceans >26.5°C, depth >50 m, latitude 5-30° (Coriolis required), low wind shear. Warm core driven by latent heat release. Coriolis spins the storm cyclonically (anticlockwise N hemisphere).', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Define Park''s response curve.', 'Quality of life trace through pre-disaster, disruption, search-and-rescue, relief, rehabilitation, reconstruction. Recovery may exceed (more resilient), match, or fall below pre-disaster level depending on aid and management.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'List four disaster mitigation strategies.', 'Hazard mapping/zoning, building codes (base isolation), early warning systems (Japan 1-min alert), education and drills, retrofitting, insurance, emergency stockpiles, community awareness.', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Define a multi-hazard zone.', 'Region exposed to several hazards (e.g. Philippines: typhoons, earthquakes, volcanism, tsunamis, landslides). One event can trigger another (typhoon -> landslide). Increases vulnerability and complicates planning.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Outline a contrasting volcanic event case study.', 'Eyjafjallajökull, Iceland 2010: VEI 4, low casualties, ash disrupted European aviation 6-8 days, $1.7bn losses. Mt Merapi, Indonesia 2010: VEI 4, 350+ deaths, 350,000 displaced, evacuated villages destroyed.', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T1', 'Tectonic Processes and Hazards', 'Why does hazard impact differ between countries?', 'Wealth funds prevention/response. Strong governance enforces codes, manages aid. LICs lack early warning, hospitals, finance — so similar magnitudes cause higher death tolls. Cultural perception shapes preparedness.', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Define a sediment cell.', 'A largely self-contained coastal section with sources, transfers and sinks of sediment between fixed boundaries (usually headlands). England and Wales are divided into 11 cells.', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Distinguish constructive and destructive waves.', 'Constructive: low height, long wavelength, low frequency (6-8/min), strong swash, weak backwash, builds beaches. Destructive: tall, short wavelength, frequent (10-14/min), weak swash, strong backwash, removes sediment.', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Name four wave-driven erosional processes.', 'Hydraulic action (waves compress air in cracks), abrasion (sediment scours), attrition (rocks knock together, become rounder), corrosion/solution (chemical dissolving — limestone, chalk).', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Describe longshore drift.', 'Sediment is moved along a coast in a zigzag pattern: swash carries material up the beach in the prevailing wind direction; backwash returns it perpendicular to shoreline. Net result: lateral transport. <svg viewBox="0 0 260 130" width="260" height="130" style="display:block;margin:6px auto"><rect x="0" y="60" width="260" height="70" fill="#F2D9A5"/><line x1="0" y1="60" x2="260" y2="60" stroke="#0B1E3F" stroke-width="1.2"/><path d="M20 100 L60 70" stroke="#0B1E3F" marker-end="url(#b2)"/><path d="M60 70 L80 100" stroke="#0B1E3F" marker-end="url(#b2)" stroke-dasharray="2 2"/><path d="M80 100 L120 70" stroke="#0B1E3F" marker-end="url(#b2)"/><path d="M120 70 L140 100" stroke="#0B1E3F" marker-end="url(#b2)" stroke-dasharray="2 2"/><path d="M140 100 L180 70" stroke="#0B1E3F" marker-end="url(#b2)"/><path d="M180 70 L200 100" stroke="#0B1E3F" marker-end="url(#b2)" stroke-dasharray="2 2"/><path d="M200 100 L240 70" stroke="#0B1E3F" marker-end="url(#b2)"/><path d="M40 30 L80 30" stroke="#B00020" marker-end="url(#b3)"/><text x="60" y="22" font-size="8" fill="#B00020" text-anchor="middle">prevailing wind</text><defs><marker id="b2" viewBox="0 0 6 6" refX="5" refY="3" markerWidth="6" markerHeight="6" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#0B1E3F"/></marker><marker id="b3" viewBox="0 0 6 6" refX="5" refY="3" markerWidth="6" markerHeight="6" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#B00020"/></marker></defs></svg>', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline the headland-bay-cave-arch-stack sequence.', 'Differential erosion of soft and hard rock creates headlands and bays. Headlands attacked from both sides: cracks → caves → caves meet (arch) → arch collapses (stack) → stack erodes (stump). Old Harry Rocks, Dorset.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline the formation of a wave-cut platform.', 'Waves erode a notch at the high-water mark; cliff above is undercut and collapses; cliff retreats inland leaving a flat rocky platform at low tide. Continued retreat creates wider platforms.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline the formation of a spit.', 'Longshore drift transports sediment past a change in coastline orientation; sediment accumulates in deeper water; secondary winds curve the end. Sheltered area behind develops salt marsh. Examples: Spurn Head, Hurst Castle.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Distinguish concordant, discordant and Dalmatian coasts.', 'Concordant: rock layers parallel to coast (e.g. Lulworth, Dorset). Discordant: layers perpendicular, headlands and bays. Dalmatian: long ridges parallel to coast partly drowned by sea-level rise (Croatia coast).', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Distinguish eustatic and isostatic sea-level change.', 'Eustatic: global change in volume of seawater (ice melt, thermal expansion). Isostatic: local change in land level (glacial rebound, subsidence). Together produce relative sea-level change.', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Distinguish emergent and submergent landforms.', 'Emergent: raised beaches, fossil cliffs (sea fell or land rose). Submergent: rias (drowned river valleys), fjords (drowned glacial valleys), Dalmatian coasts.', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'List four hard-engineering coastal defences and one drawback each.', 'Sea wall (expensive, ugly), groynes (starve down-drift coast), rock armour/rip-rap (visual impact), revetment (costly maintenance), gabions (rust over time). Defer rather than solve.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'List four soft-engineering coastal defences.', 'Beach nourishment (replenish sand), dune regeneration (planting marram grass), managed retreat/coastal realignment, salt-marsh restoration. Cheaper, more sustainable, but slower-acting.', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Define Shoreline Management Plans (SMPs).', 'UK strategic plans for coastal stretches: hold the line, advance the line, managed retreat, or no active intervention. Reviewed every 5-10 years and balance economic, social and environmental factors.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline the Holderness coastline.', 'East Yorkshire — fastest eroding coast in Europe (~1.8 m/yr). Boulder clay cliffs, North Sea fetch, longshore drift south. Mappleton groynes (1991) protected village but accelerated erosion at Cowden — terminal-groyne syndrome.', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Define glacial systems and key processes.', 'Open systems with inputs (snowfall, avalanches), stores (ice, meltwater) and outputs (meltwater discharge, calving). Processes: plucking (ice freezes onto bedrock and plucks blocks), abrasion (rock fragments scour bedrock), freeze-thaw weathering.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline the formation of a corrie.', 'Snow accumulates in a north-facing hollow, compresses to firn then ice. Plucking and abrasion deepen the hollow; rotational movement scoops it into an armchair shape. After deglaciation, a tarn (lake) often fills it.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Distinguish arête and pyramidal peak.', 'Arête: knife-edged ridge between two corries (Striding Edge, Lake District). Pyramidal peak: where three or more corries erode back-to-back (Matterhorn, Snowdon).', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline the formation of a U-shaped valley.', 'A pre-existing V-shaped river valley is widened, deepened and straightened by glacier ice. Truncated spurs replace interlocking ones. After deglaciation: misfit stream, sometimes ribbon lakes (Wastwater).', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Distinguish drumlin, esker and erratic.', 'Drumlin: streamlined hill of glacial till (Cumbrian fells). Esker: sinuous ridge of fluvio-glacial sand and gravel (deposited by sub-glacial stream). Erratic: large rock transported far from origin (e.g. Norber erratics, Yorkshire).', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T2', 'Landscape Systems, Processes and Change', 'Outline pressures on a glacial environment (e.g. Antarctic).', 'Climate change accelerates ice loss; tourism (cruise ships, scientific bases) leaves footprint; mineral exploration interest; Antarctic Treaty (1961) suspends territorial claims and bans mining. Madrid Protocol (1991) extended environmental protections.', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'List the four major stores of the global water cycle.', 'Oceans (~97%), cryosphere/ice (~2%), groundwater (~0.7%), surface water and atmosphere (<0.1%). Lithosphere holds tiny amounts in rocks.', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Sketch the global water cycle.', 'Solar energy drives evaporation from oceans, vegetation transpires, vapour rises and condenses, precipitates over land/oceans; runoff and groundwater return to sea. <svg viewBox="0 0 260 160" width="260" height="160" style="display:block;margin:6px auto"><rect x="0" y="120" width="260" height="40" fill="#9CC3E5"/><polygon points="120,120 200,120 220,80 130,80" fill="#A8D08D"/><circle cx="60" cy="35" r="12" fill="#E7E6E6"/><circle cx="180" cy="30" r="14" fill="#E7E6E6"/><path d="M40 110 Q40 80 60 50" stroke="#0B1E3F" fill="none" marker-end="url(#b4)"/><path d="M150 90 Q150 70 170 45" stroke="#0B1E3F" fill="none" marker-end="url(#b4)"/><path d="M210 50 Q220 80 220 110" stroke="#0B1E3F" fill="none" marker-end="url(#b4)"/><defs><marker id="b4" viewBox="0 0 6 6" refX="5" refY="3" markerWidth="6" markerHeight="6" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#0B1E3F"/></marker></defs><text x="20" y="80" font-size="8" fill="#0B1E3F">evap</text><text x="125" y="65" font-size="8" fill="#0B1E3F">transp</text><text x="220" y="80" font-size="8" fill="#0B1E3F">precip</text></svg>', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Define a drainage basin and key terms.', 'Drainage basin: area of land drained by a river and its tributaries. Watershed: high-ground boundary. Source: where the river begins. Mouth: where it enters the sea. Confluence: junction of two streams.', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Sketch the drainage basin (inputs, stores, flows, outputs).', 'Input: precipitation. Stores: interception, surface, soil moisture, groundwater, channel. Flows: surface runoff, throughflow, infiltration, percolation, baseflow. Outputs: evaporation, transpiration, channel discharge.', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Define a storm hydrograph and explain key features.', 'A graph of river discharge against time after a storm. Lag time: gap between peak rainfall and peak discharge. Steeper rising limb / shorter lag indicate flashier basin (urbanised, impermeable, steep, saturated).', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'List four physical and four human factors affecting flood risk.', 'Physical: heavy/prolonged rainfall, snowmelt, impermeable rock, steep relief, antecedent saturation. Human: urbanisation, deforestation, channel modification, climate change.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Compare positive and negative feedbacks in the water cycle.', 'Positive: warming -> more evaporation -> more atmospheric water vapour -> more warming. Negative: more cloud cover -> higher albedo -> less heating -> reduced evaporation. Net effect uncertain in models.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Define the water budget and what surplus/deficit mean.', 'Water budget: balance of precipitation and potential evapotranspiration. Surplus: P > PET (winter), recharges soil. Deficit: PET > P (summer), uses up soil moisture, plants stressed.', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Define water scarcity and water stress.', 'Water stress: <1700 m3 per person per year. Water scarcity: <1000 m3. Absolute scarcity: <500 m3. Causes: physical (low rainfall) or economic (lack of infrastructure). Affects ~2 billion people.', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Distinguish blue, green and grey water.', 'Blue: liquid surface and groundwater (rivers, lakes, aquifers). Green: rainwater stored in soil, used by plants. Grey: wastewater volume needed to dilute pollution to safe levels.', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Explain how climate change affects the water cycle.', 'Warmer air holds more moisture (~7%/°C, Clausius-Clapeyron); intensifies extreme rainfall and droughts; expands subtropical dry zones; shifts seasonal precipitation; shrinks glaciers, threatening dry-season flow.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'How does deforestation affect the water cycle?', 'Reduces interception and transpiration. Increases overland flow and erosion. Lowers regional rainfall (Amazon ''flying rivers''). Raises temperatures locally through reduced evapotranspiration cooling.', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Outline causes and consequences of the Aral Sea disaster.', 'Soviet 1960s diversion of Amu/Syr Darya for cotton irrigation; Aral lost ~90% volume by 2010. Consequences: collapse of fisheries, salinised soils, dust storms, public health crisis, lost climate-moderating effect.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Define a transboundary water resource with example.', 'A water source crossing borders, requiring cooperation. Examples: Nile (Egypt-Sudan-Ethiopia GERD dispute), Mekong (six countries), Indus Waters Treaty (India-Pakistan, 1960 — survived three wars).', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'List four hard-engineering water management strategies.', 'Mega-dams (Three Gorges, China), reservoirs, water transfer schemes (South-North China), desalination plants (Israel, Saudi Arabia), inter-basin canals. Capital-intensive; environmental and social impacts.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'List four sustainable water strategies.', 'Drip irrigation, recycling/reuse (Singapore NEWater), rainwater harvesting, demand management/metering, restoring wetlands, integrated catchment management, dual-flush toilets, fixing leaks.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'How does water pricing affect demand?', 'Pricing reflects scarcity, encouraging efficiency. Tiered tariffs make large users pay more (block tariff). Risks: regressive impact on low-income users; need for safety net (essential allocation, social tariffs).', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Outline integrated drainage basin management.', 'Coordinated stewardship across all catchment users (farms, cities, ecology). UK Catchment-Based Approach. Targets quality (WFD), supply, flooding, biodiversity. Requires governance and stakeholder buy-in.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'Explain how a Mediterranean climate creates seasonal water stress.', 'Hot dry summer (subtropical high) coincides with peak demand (irrigation, tourism, AC). Wet mild winter recharges aquifers. Causes summer droughts; high abstraction risks salinisation in coastal aquifers (Spain, California).', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T3', 'The Water Cycle and Water Insecurity', 'How does water scarcity link to conflict?', 'Disputes over shared resources can escalate (Israel-Palestine West Bank aquifer; Tigris-Euphrates between Turkey, Syria, Iraq). Often water sits within wider political tensions; cooperation is more common than ''water wars''.', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'List the four major stores of the global carbon cycle.', 'Lithosphere (sedimentary rocks, fossil fuels — by far largest), oceans (dissolved CO2, biological), terrestrial biosphere (vegetation, soils), atmosphere (CO2, CH4 — smallest but climate-critical).', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Distinguish fast and slow carbon cycles.', 'Fast: photosynthesis, respiration, decomposition, ocean exchange — operates over days to centuries. Slow: weathering of silicates, sedimentation, volcanism — operates over millions of years.', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Sketch the global carbon cycle.', 'Atmosphere ↔ photosynthesis (vegetation) and respiration; vegetation → soil via decomposition; oceans absorb/release CO2; weathering removes; volcanism returns; fossil fuel combustion releases stored. <svg viewBox="0 0 280 160" width="280" height="160" style="display:block;margin:6px auto"><rect x="20" y="20" width="240" height="30" fill="#E7E6E6"/><text x="140" y="38" font-size="9" fill="#0B1E3F" text-anchor="middle">Atmosphere (CO2)</text><rect x="20" y="80" width="100" height="30" fill="#A8D08D"/><text x="70" y="98" font-size="9" fill="#0B1E3F" text-anchor="middle">Vegetation</text><rect x="160" y="80" width="100" height="30" fill="#9CC3E5"/><text x="210" y="98" font-size="9" fill="#0B1E3F" text-anchor="middle">Oceans</text><rect x="160" y="125" width="100" height="20" fill="#454545"/><text x="210" y="139" font-size="9" fill="white" text-anchor="middle">Fossil fuels</text><line x1="50" y1="50" x2="50" y2="78" stroke="#0B1E3F" marker-end="url(#b5)"/><line x1="90" y1="78" x2="90" y2="52" stroke="#0B1E3F" marker-end="url(#b5)"/><line x1="200" y1="123" x2="200" y2="55" stroke="#B00020" stroke-width="1.2" marker-end="url(#b6)"/><text x="205" y="80" font-size="7" fill="#B00020">combust</text><defs><marker id="b5" viewBox="0 0 6 6" refX="5" refY="3" markerWidth="6" markerHeight="6" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#0B1E3F"/></marker><marker id="b6" viewBox="0 0 6 6" refX="5" refY="3" markerWidth="6" markerHeight="6" orient="auto"><path d="M0,0 L6,3 L0,6 z" fill="#B00020"/></marker></defs></svg>', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Outline the ocean carbon pumps.', 'Physical (solubility) pump: cold polar water dissolves CO2, sinks, locks C in deep ocean for centuries. Biological pump: phytoplankton photosynthesise; dead matter sinks (''marine snow'') sequestering C in sediments.', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Why does the Amazon matter for the carbon cycle?', 'Stores ~150-200 Pg C in biomass and soils. Transpires huge water vapour driving regional rainfall. Deforestation reduces both the carbon sink and the moisture flux, risking ''dieback'' tipping points.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'How are land-use change and farming affecting the carbon cycle?', 'Deforestation releases stored C and reduces sinks. Ploughing exposes/oxidises soil organic matter. Drainage of peatlands releases CO2. Livestock and rice paddies emit methane (~25× CO2 GWP).', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Define energy security.', 'Reliable access to energy at affordable prices. Components: availability, accessibility, affordability, acceptability (low environmental and social cost). Threatened by import dependence, conflict, depletion.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'List the components of the energy mix.', 'Coal, oil, natural gas (fossil), nuclear, hydro, wind, solar, biomass/biofuel, geothermal, tidal/wave. Mix varies by country: France ~70% nuclear, Norway ~95% hydro, Saudi Arabia oil-dominant.', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Define peak oil and Hubbert''s curve.', 'Peak oil: point of maximum extraction, after which production declines. Hubbert''s 1956 prediction of US peak in ~1970 was broadly correct (until shale revolution from 2008 reopened US production).', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Distinguish unconventional and conventional fossil fuels.', 'Conventional: vertically drilled, naturally pooled, easily extracted. Unconventional: shale gas/oil (fracking), tar sands, deep-water, Arctic — higher cost, more environmental impact.', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Outline the renewable energy transition.', 'Global renewable share rose from ~20% (2010) to ~30% (2024) of electricity. Solar PV cost ~90% lower since 2010. Wind, solar dominate new capacity. Challenges: intermittency, storage, grid upgrades, mineral demand.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Outline the geopolitics of energy in Russia/Ukraine.', 'Russia supplied ~40% of EU gas pre-2022. Invasion of Ukraine triggered EU diversification (Norwegian gas, US LNG, accelerated renewables, restart of coal). Energy weaponised; Nord Stream pipeline sabotaged.', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Outline OPEC and its role.', 'Organization of Petroleum Exporting Countries (1960). Coordinates oil production policy among 13 members; OPEC+ adds Russia and others. Aims to stabilise prices and revenue. Production cuts in 2023-24 supported prices.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'List four impacts of fossil fuel extraction.', 'Air pollution and emissions, water contamination (fracking), oil spills (Deepwater Horizon 2010), habitat destruction, induced seismicity, geopolitical conflict, methane leakage, social disruption.', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'List four climate change impacts.', 'Sea-level rise (~3.4 mm/yr), Arctic ice loss, more extreme weather, ocean acidification (pH ~8.2 → 8.1), shifts in species ranges, glacier retreat, permafrost thaw, agricultural disruption.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'List four positive feedbacks accelerating climate change.', 'Ice-albedo (less ice -> more absorbed solar), permafrost thaw releasing CH4, forest dieback releasing C, ocean warming reducing CO2 solubility, slowed thermohaline circulation.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Outline mitigation strategies for climate change.', 'Cut emissions: renewables, EVs, energy efficiency, low-carbon heating, food system change. Carbon capture and storage. Afforestation. Reduce deforestation (REDD+). International agreements (Paris 2015 - 1.5°C target).', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Outline adaptation strategies for climate change.', 'Sea defences and coastal realignment, drought-resistant crops, water resource planning, urban cooling (green roofs, white surfaces), early warning systems, shifting agricultural zones, redesigned infrastructure.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Define the Paris Agreement (2015).', 'A UNFCCC treaty signed by ~196 parties. Aims to limit warming to ''well below 2°C'' above pre-industrial, pursuing 1.5°C. Each country sets Nationally Determined Contributions (NDCs), reviewed every 5 years.', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T4', 'The Carbon Cycle and Energy Security', 'Why is the Arctic warming faster than the global average?', 'Polar amplification: ice-albedo feedback (less reflective sea ice -> more absorbed solar -> more melt). Atmospheric circulation. Heat transported by ocean currents. Arctic warming ~3-4× global rate.', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define globalisation.', 'Growing integration of national economies through international trade, capital flows, migration, technology transfer and cultural exchange. Driven by transport costs, ICT, and trade liberalisation.', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'List four causes of globalisation.', 'Falling transport/communication costs, trade liberalisation (WTO/GATT), ICT advances, deregulation of capital markets, end of Cold War, growth of multinationals (TNCs), rising consumer incomes.', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define KOF index of globalisation.', 'Composite index measuring economic, social and political dimensions. Includes trade, FDI, internet penetration, international tourism, treaty memberships. Singapore, Switzerland and Netherlands typically score highest.', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define a TNC and explain its role in globalisation.', 'Transnational Corporation: a firm operating in multiple countries (Apple, Toyota, Unilever). Drives globalisation by offshoring production, FDI, supplying global markets, transferring technology — but accused of tax avoidance, exploitation.', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define a Special Economic Zone (SEZ).', 'A geographic region with relaxed regulation/taxes to attract FDI. Shenzhen, China''s first SEZ (1980), grew from 30,000 to 12 million people. Catalysed China''s manufacturing boom; 4500+ SEZs globally.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'List the four stages of economic integration.', 'Free trade area (no tariffs), customs union (common external tariff), single/common market (free factor movement), economic and monetary union (common currency). EU progressed through all four.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Outline the WTO''s main role.', 'Promotes liberal world trade by negotiating multilateral agreements, enforcing the Most-Favoured-Nation principle and arbitrating disputes between members. Successor to GATT (1995). 164 members; struggles with stalled Doha round.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define switched-on and switched-off places.', 'Switched-on: well-connected to global flows of capital, people, goods (London, NYC, Shanghai). Switched-off: poor connections, peripheral economies (Sahel, Central Asia interior). Inequality reinforced by global system.', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Outline winners and losers of globalisation.', 'Winners: emerging economies (China, India), TNCs and shareholders, skilled labour in HICs, consumers (cheaper goods). Losers: low-skilled labour in HICs (deindustrialisation), workers in sweatshops, environment, vulnerable cultures.', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define cultural homogenisation and hybridisation.', 'Homogenisation: dominant cultures (often US/Western) spread, eroding local distinctiveness (McDonaldisation, Hollywood). Hybridisation: cultures mix to produce new forms (London curry, K-pop in West, Bollywood-Hollywood crossover).', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'List four economic impacts of globalisation in HICs.', 'Deindustrialisation (UK manufacturing share fell from ~30% in 1970 to ~9% by 2020), service-sector growth, regional inequality (north-south UK), wage stagnation for low-skilled, rising inequality.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'List four economic impacts of globalisation in NEEs.', 'Rapid industrialisation (China factory of the world), urbanisation, rising incomes (China''s GDP/cap rose ~40× since 1980), inequality (Gini), environmental degradation, financial volatility (1997 Asian crisis).', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Outline the global shift in manufacturing.', 'Movement of manufacturing from HICs to NEEs since 1970s, driven by cheaper labour, weaker regulation. China rose to ~28% of global manufacturing. Now Vietnam, Bangladesh capture textile from China as wages rise.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define migration push and pull factors.', 'Push: war, poverty, drought, persecution, lack of opportunity. Pull: jobs, family reunification, peace, education, healthcare, freedom. Lee''s model adds intervening obstacles (cost, border controls).', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define remittances and their importance.', 'Money sent home by migrants. Globally ~$650bn/yr (2022) — exceeds FDI to LICs. Major source of income for Philippines (~10% GDP), Tonga (~40%), Tajikistan. Vulnerable to host-country recessions.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define brain drain.', 'Emigration of skilled workers from LICs/MICs to HICs (doctors, engineers, scientists). Drains source country of investment and capability. Sub-Saharan Africa''s health worker emigration to UK, US is widely studied.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'List four environmental impacts of globalisation.', 'Higher emissions from transport (~14% of global), deforestation for plantations (palm oil), e-waste (~50 Mt/yr), ocean plastic, biodiversity loss, water and air pollution near production hubs.', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Outline ethical/local responses to globalisation.', 'Fair trade (Fairtrade Foundation 1992, ~£1.6bn UK retail sales), local sourcing, transition towns, ethical investment, anti-globalisation movements (Seattle 1999), CittaSlow (slow cities), buy local campaigns.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Define re-shoring and explain why it occurs.', 'Returning production to the home country. Drivers: rising wages abroad (China), automation reducing labour-cost advantage, supply chain risks (Covid, Ukraine war), tariffs (Trump 2018, 2024), national security concerns (semiconductors).', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T5', 'Globalisation', 'Outline the de-globalisation trend (post-2008).', 'Slowdown in trade growth, more protectionism (US-China tariffs), Brexit, Covid-disrupted supply chains, semiconductor decoupling, Russia sanctions. Trade share of GDP fell from peak ~61% (2008) to ~57% (2020s).', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Distinguish space, place and locale.', 'Space: an area defined by coordinates. Place: space invested with meaning by people (Tuan). Locale: setting in which everyday life happens (Agnew). Place is therefore relational and dynamic.', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define endogenous and exogenous factors that shape place.', 'Endogenous (internal): physical geography, demography, land use, economy, built environment, history. Exogenous (external): connections to other places, migration, capital flows, government policy, globalisation.', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define topophilia and topophobia.', 'Topophilia (Tuan, 1974): the affective bond between people and place — love of place. Topophobia: fear or dislike of place — common in places associated with crime, decay, traumatic memory.', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Distinguish insider and outsider perspectives.', 'Insider: born or long-resident, share traditions, language, networks; place-attached. Outsider: temporary or unfamiliar; may romanticise or stereotype. Status fluid — gentrifiers can shift between.', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define social, ethnic and economic diversity in a place.', 'Social: variation in age, household type, religion. Ethnic: variation in cultural/national identities (e.g. London ~40% non-white British). Economic: range of income levels, occupations, deprivation indicators.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'How does the IMD measure deprivation?', 'UK Index of Multiple Deprivation combines seven domains: income, employment, education, health, crime, housing, living environment. Areas ranked into deciles. Allows place-by-place comparison of need.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline four causes of urban deprivation.', 'Deindustrialisation (loss of factories), structural unemployment, poor housing stock, low investment, weak schools, transport poverty, in-migration of low-income groups, decline of local industries.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline gentrification with one named example.', 'In-migration of higher-income residents into a previously low-income area, refurbishing housing and changing local amenities. Displaces original residents through rising rents. Examples: Notting Hill, Brixton, Hackney, Brooklyn.', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline an urban regeneration scheme (London Docklands).', '1981 LDDC established. £8.7bn investment by 1998. Canary Wharf, DLR, City Airport. 80,000+ jobs. Critique: original communities largely excluded; gentrification displaced low-income residents.', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline a rural rebranding strategy with example.', 'Rebranding aims to attract visitors/investors. Cornwall: Eden Project (£2bn local economic impact since 2001), Hall for Cornwall, food/drink tourism. Trade-offs: housing affordability for locals.', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define rural-urban continuum.', 'Spectrum from deep countryside through accessible rural, suburb, inner suburb, inner city. Pace of life, density, services, demographic profile vary along it. Boundaries blur as commuter belts extend.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline counter-urbanisation drivers.', 'Improved transport/IT (commute, remote work), perception of better quality of life (lower crime, cleaner air, schools), housing affordability, retirement. Covid-19 accelerated UK ''race for space'' (London out-migration ~80,000 in 2020-21).', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define rural diversity (services, culture, deprivation).', 'Variation between rural areas: tourist hotspots, commuter villages, working farms, deprived ex-industrial. Service decline (post offices, pubs, banks) hits remote rural; AONB designation may resist change but also limit affordable housing.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define ethnic enclave and outline reasons for clustering.', 'A neighbourhood with high concentration of one ethnic group. Reasons: chain migration, mutual support, language/cultural amenities, discrimination in housing markets. Examples: Tower Hamlets (Bangladeshi), Brixton (Caribbean).', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline how migration shapes place identity.', 'Migrants reshape places (cultural quarters, religious buildings, food, languages). Brick Lane''s curry mile reflects east London Bangladeshi identity. Polish shops appeared in UK towns post-2004 EU enlargement; some ''closed'' post-Brexit.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'List four ways place is represented.', 'Statistics (census, IMD), films, novels, paintings, photographs, music, postcards, tourist boards, news media, social media (#hashtags create new place identities).', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define lived experience and how it is studied.', 'Everyday meanings of a place to its residents. Accessed through ethnography, interviews, oral histories, participant observation, mental maps, photo elicitation — qualitative methods that surface what statistics cannot.', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Define resilience of place.', 'A place''s ability to absorb shocks (flooding, deindustrialisation, pandemics) and adapt. Drivers: economic diversity, social capital, governance, infrastructure. Detroit struggled; Pittsburgh transitioned to medicine/education.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Outline community-led place-making.', 'Local residents shape their place through neighbourhood plans, community land trusts, public art, festivals, restoration projects. Examples: Hackney Wick, Granby Four Streets (Liverpool, Turner Prize 2015).', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T6', 'Diverse Places', 'Compare a contrasting place study (your own + one other).', 'Choose two places (e.g. local urban + rural Cornwall), compare endogenous and exogenous factors, demographic and economic profiles, representations, lived experiences and management strategies — the ''Diverse Places'' core skill.', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define a superpower.', 'A state with ability to project influence globally — military, economic, cultural, political. Currently the US is the sole hyperpower; China is a rising challenger; EU and Russia have regional reach.', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline Mackinder''s heartland theory.', '1904 paper: ''Whoever controls Eastern Europe controls the heartland; whoever controls the heartland commands the world''. Geopolitically influential — explains containment of Russia in Cold War.', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Distinguish hard, soft and smart power (Nye).', 'Hard: coercive — military, economic sanctions. Soft: attractive — culture, ideology, diplomacy (Hollywood, BBC, English language). Smart: blends both. China''s Belt and Road combines investment with strategic positioning.', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define unipolar, bipolar and multipolar world.', 'Unipolar: one dominant power (post-1989 USA). Bipolar: two rivals (USA-USSR Cold War). Multipolar: several great powers competing (pre-WWI Europe, today USA-China-EU-Russia-India).', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline the rise of China as an emerging superpower.', '~1.4bn population, world''s 2nd largest economy by GDP, largest by PPP. Strategy: export-led growth, manufacturing base, infrastructure (BRI), military modernisation, tech rivalry, S China Sea claims.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define the BRICS+ group.', 'Brazil, Russia, India, China, South Africa formed in 2009; expanded 2024 with Iran, UAE, Egypt, Ethiopia. Counter-balance to G7 economic governance. Goal: influence in IMF/World Bank, alternative payments, dedollarisation.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define the G7/G20.', 'G7: USA, UK, France, Germany, Italy, Japan, Canada — leading industrialised democracies. G20: 19 countries + EU, accounting for ~80% global GDP. Forum for international economic cooperation post-2008.', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define IGOs and list four examples.', 'Intergovernmental Organisations: UN, NATO, IMF, World Bank, WTO, WHO, OECD, OPEC. Pool sovereignty for collective action; superpowers often dominate (US in IMF, China in BRICS-affiliated NDB).', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define superpower spheres of influence.', 'Areas where a superpower''s political, economic and cultural reach is dominant. US: Americas, NATO Europe, Middle East. China: East Asia, expanding via BRI. Russia: post-Soviet space, parts of Africa via Wagner.', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline the Belt and Road Initiative.', 'China''s ~$1tn (since 2013) infrastructure programme (ports, rail, energy) across ~150 countries. Aims to revive Silk Road trade, expand Chinese influence, secure resources. Critics: ''debt trap diplomacy'' (Sri Lanka Hambantota port).', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define neo-colonialism.', 'When former colonial powers (or new powers) maintain economic/political dominance over former colonies through trade, aid conditionality, FDI, military bases. France in francophone Africa; China in resource-extraction in DRC.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline TNCs and superpower projection.', 'TNCs from superpowers project economic and cultural influence (Apple, Google, McDonald''s, Disney). 60% of largest 100 TNCs are US-headquartered. Tax avoidance and labour standards generate friction (EU vs Big Tech).', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define energy security in superpower competition.', 'Reliable access to affordable energy. US shale revolution made it net exporter (~2019). China heavily dependent on Middle East oil through Malacca Strait — strategic vulnerability driving BRI infrastructure.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Why is the South China Sea geopolitically significant?', '~$3.4tn trade passes annually (~30% global trade). Rich fisheries, oil/gas. China claims Nine-Dash Line; rejected by 2016 PCA ruling. US ''freedom of navigation'' patrols; ASEAN states (Vietnam, Philippines) push back.', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline the Russia-Ukraine war as a superpower issue.', '2022 invasion broke European post-1945 order. NATO unity strengthened (Finland, Sweden joined 2023-24). Energy weaponised. Sanctions on Russia. China-Russia ''no-limits'' partnership but China cautious. War remains stalemated.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define soft power and provide three indicators.', 'A state''s ability to attract and persuade. Indicators: media reach (BBC), film exports (Hollywood), university league tables (US/UK), Nobel Prizes, tourism, cultural influence (K-pop, Bollywood). Joseph Nye, 1990.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'List three challenges to US hegemony.', 'Rise of China, Russia revisionism, fragmenting alliance system, debt and political polarisation, populism, climate change, technology rivalry (AI, semiconductors), de-dollarisation moves.', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline India as an emerging power.', '~1.4bn population, 5th-largest economy by GDP. ''Demographic dividend'' (median age 28). Tech and services hub; nuclear-armed; neutral-ish in Russia-Ukraine. Member of QUAD (with US, Japan, Australia) — strategic counter to China.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Define climate diplomacy.', 'Use of climate negotiations as foreign policy. UNFCCC/COP process; small island states (AOSIS) press for 1.5°C; superpowers trade emissions cuts for technology transfers. China-US bilateral track key to Paris Agreement (2015).', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T7', 'Superpowers', 'Outline the Arctic geopolitical contest.', 'Melting sea ice opens shipping routes (NSR through Russia) and resource access (oil, gas). 8 Arctic Council states. Russia militarising; NATO members (US, Canada, Norway) responding. Climate change driving competition.', 20, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'List four indicators of human development.', 'Life expectancy, GNI per capita PPP, mean/expected years of schooling (HDI components). Adult literacy, maternal mortality, infant mortality, Gini coefficient, gender inequality index, multidimensional poverty index.', 1, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'List the three components of HDI.', 'Life expectancy at birth (health), mean and expected years of schooling (education), GNI per capita PPP (income). Combined into a 0-1 index. UN HDR ranks ~190 countries annually.', 2, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define gender inequality and three measures.', 'Systemic disadvantage of one gender. Measures: GII (UN — reproductive health, empowerment, labour market), GGGI (WEF — gender gap index), maternal mortality ratio, female labour force participation.', 3, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define epidemiological transition (Omran).', 'Disease patterns shift as society develops: from infectious diseases (TB, cholera) and famine, to chronic diseases (heart disease, cancer), to ''emerging'' diseases (Covid-19, antibiotic-resistant infections).', 4, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline a contrasting health case study.', 'UK NHS: universal healthcare, ageing population, NCDs dominate, life expectancy ~81. Sub-Saharan Africa: HIV/AIDS, malaria, malnutrition; life expectancy 60-65 but rising as ART scaled up.', 5, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline how vector-borne disease distribution is influenced by climate.', 'Mosquitoes (malaria, dengue) require warmth and standing water. Climate change is shifting ranges polewards and to higher altitudes (highland malaria in Kenya). Tsetse fly limits African livestock to certain zones.', 6, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Why is globalisation linked to pandemics?', 'Air travel moves pathogens across continents in hours (SARS 2003, H1N1 2009, Covid-19 2020). Urbanisation concentrates susceptible populations. Habitat encroachment increases zoonotic spillover (Ebola, Nipah, Covid-19).', 7, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define human rights and outline UN framework.', 'Universal entitlements regardless of citizenship — life, liberty, freedom from torture, freedom of religion. Universal Declaration of Human Rights (1948). ICCPR and ICESCR (1966) formalise; UN Human Rights Council monitors.', 8, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define the ECHR and its role.', 'European Convention on Human Rights (1950). 46 member states. European Court of Human Rights (Strasbourg) hears individual complaints. Influences UK law via Human Rights Act 1998. Subject to political debate.', 9, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define democracy and the Democracy Index.', 'Government by the people via free elections, rule of law, civil liberties. Democracy Index (Economist Intelligence Unit) ranks ~165 countries: full democracy, flawed democracy, hybrid, authoritarian. Trend: democratic recession 2010s-20s.', 10, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define corruption and how it is measured.', 'Abuse of public office for private gain. Transparency International''s Corruption Perceptions Index (CPI) ranks ~180 countries. Weakens institutions, deters investment, distorts public spending — strong negative correlation with HDI.', 11, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define geopolitical intervention.', 'A state or IGO acting in another state''s affairs — diplomatic pressure, sanctions, peacekeeping, military force. Legitimacy contested: UN Security Council authorisation provides cover but P5 vetoes block action.', 12, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Define R2P (Responsibility to Protect).', 'A 2005 UN principle: states have responsibility to protect populations from genocide, war crimes, ethnic cleansing, crimes against humanity. International community may intervene if state fails. Invoked in Libya 2011.', 13, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'List four types of international aid.', 'Bilateral (country to country), multilateral (via World Bank, UN), humanitarian/emergency (Red Cross, MSF), tied (conditional on buying donor goods/services), concessional loans, debt relief.', 14, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline strengths and weaknesses of foreign aid.', 'For: relieves poverty, builds capacity, addresses humanitarian crises. Against: dependency, corruption, distorts incentives, ''Dutch disease'' from aid inflows, conditionality may impose poor policy.', 15, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline a successful aid intervention.', 'Bangladesh: BRAC (largest NGO globally), Grameen Bank microfinance, oral rehydration therapy, vaccination — under-5 mortality fell from 240 (1970) to 28 (2024) per 1000 live births.', 16, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline a failed aid intervention.', 'Live Aid Ethiopia 1985 raised $245m but emergency aid did not address underlying drought, civil war, governance. Mengistu regime used food aid as weapon. Lessons: tied aid, corrupted distribution, no long-term capacity building.', 17, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline a military humanitarian intervention.', 'Libya 2011: UN Resolution 1973 authorised no-fly zone after Gaddafi threatened civilians. NATO airstrikes helped overthrow regime. Aftermath: state collapse, civil war ongoing, migration crisis. Mixed legacy of R2P.', 18, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'List four post-conflict development challenges.', 'Rebuilding infrastructure, reconciling ethnic divisions, demobilising combatants, restoring rule of law, economic recovery, refugee return, dealing with trauma, addressing root causes (ethnicity, resources).', 19, 'alevel'),
  ('Geography', 'Edexcel', 'T8', 'Health, Human Rights and Intervention', 'Outline how to measure development progress.', 'Use multiple indicators not GDP alone — HDI for socio-economic, GII for gender, IHDI inequality-adjusted, MPI multi-dimensional poverty. Sustainable Development Goals (17 SDGs to 2030). Allows comparative country progress monitoring.', 20, 'alevel');
